def int_to_roman(n):
    if not isinstance(n, int) or isinstance(n, bool) or not 1 <= n <= 3999:
        raise ValueError("n must be an integer in 1..3999")
    table = (
        (1000, "M"), (900, "CM"), (500, "D"), (400, "CD"),
        (100, "C"), (90, "XC"), (50, "L"), (40, "XL"),
        (10, "X"), (9, "IX"), (5, "V"), (4, "IV"), (1, "I"),
    )
    result = []
    for value, symbol in table:
        count, n = divmod(n, value)
        result.append(symbol * count)
    return "".join(result)


def roman_to_int(s):
    if not isinstance(s, str):
        raise ValueError("s must be a string")
    roman = s.strip().upper()
    if not roman:
        raise ValueError("empty string is not a valid Roman numeral")
    values = {"I": 1, "V": 5, "X": 10, "L": 50, "C": 100, "D": 500, "M": 1000}
    total = 0
    prev = 0
    for ch in reversed(roman):
        if ch not in values:
            raise ValueError("invalid Roman numeral character: %r" % ch)
        current = values[ch]
        if current < prev:
            total -= current
        else:
            total += current
            prev = current
    if not 1 <= total <= 3999 or int_to_roman(total) != roman:
        raise ValueError("not a valid standard Roman numeral: %r" % s)
    return total
